import pandas as pd
import numpy as np

df = pd.read_csv('custom_dataset.csv')

correlation = df['process_temp'].corr(df['yield_score'])

if abs(correlation) >= 0.7:
    strength = "strong"
elif abs(correlation) >= 0.4:
    strength = "moderate"
else:
    strength = "weak"

if correlation > 0:
    direction = "positive"
else:
    direction = "negative"

result = {
    'pearson_correlation': correlation,
    'correlation_strength': strength,
    'correlation_direction': direction,
    'has_correlation': abs(correlation) >= 0.4,
    'interpretation': f"There is a {strength} {direction} correlation ({correlation:.4f}) between process_temp and yield_score."
}

print(result)
